python -c "
import sys, json, re
try:
    data = json.load(sys.stdin)
except:
    sys.exit(0)
fp = (data.get('tool_input', {}).get('file_path') or '').replace('\\', '/')
if 'docs/sprints' not in fp and 'BACKLOG' not in fp:
    sys.exit(0)
try:
    with open('docs/backlog/BACKLOG.md', 'r', encoding='utf-8') as f:
        content = f.read()
    blocked = re.findall(r'###.*?blocked.*', content, re.IGNORECASE)
    if blocked:
        ids = [re.search(r'(US-|PREC-|PJN-|COLLAB-|WHATSAPP-|AI-)\w+', b) for b in blocked]
        ids = [i.group(0) for i in ids if i]
        if ids:
            print(json.dumps({'systemMessage': 'ADVERTENCIA: Las siguientes historias estan BLOQUEADAS y NO deben planificarse:\n' + chr(10).join('  - ' + i for i in ids)}))
except:
    pass
"
